const csvText = $input.first().json.data;

function parseCSV(text) {
  const rows = [];
  const lines = text.replace(/\r/g, '').split('\n');
  for (const line of lines) {
    if (!line.trim()) continue;
    const row = [];
    let inQuote = false, cur = '';
    for (let i = 0; i < line.length; i++) {
      const ch = line[i];
      if (ch === '"') { inQuote = !inQuote; continue; }
      if (ch === ',' && !inQuote) { row.push(cur.trim()); cur = ''; continue; }
      cur += ch;
    }
    row.push(cur.trim());
    rows.push(row);
  }
  return rows;
}

const rows = parseCSV(csvText);

let headerRowIdx = -1;
for (let i = 0; i < Math.min(rows.length, 5); i++) {
  if (rows[i].some(cell => cell.toLowerCase().includes('suplemento'))) {
    headerRowIdx = i;
    break;
  }
}
if (headerRowIdx === -1) headerRowIdx = 0;

const mainHeaders = rows[headerRowIdx].map(h => h.toLowerCase().trim());
const subHeaders = (headerRowIdx + 1 < rows.length) ? rows[headerRowIdx + 1].map(h => h.toLowerCase().trim()) : [];

let idxName = -1, idxPrice = -1, idxStock = -1, idxCategory = -1, idxDoc = -1, idxCost = -1;

for (let i = 0; i < mainHeaders.length; i++) {
  const h = mainHeaders[i];
  if (h.includes('suplemento') || h.includes('alimento')) { idxName = i; }
  else if (h.includes('categor') || h.includes('objetivo')) { idxCategory = i; }
  else if (h.includes('costo') || h === '$ costo') { idxCost = i; }
  else if (h.includes('venta') || h === '$ venta') { idxPrice = i; }
  else if (h.includes('link') || h.includes('doc')) { idxDoc = i; }
}

if (idxPrice === -1) {
  for (let i = 0; i < mainHeaders.length; i++) {
    if ((mainHeaders[i].includes('precio') || mainHeaders[i].includes('price')) && i !== idxCost) {
      idxPrice = i; break;
    }
  }
}

for (let i = 0; i < subHeaders.length; i++) {
  if (subHeaders[i].includes('inventario') || subHeaders[i].includes('stock')) {
    idxStock = i; break;
  }
}

if (idxName === -1) idxName = 1;
if (idxCategory === -1) idxCategory = 0;
if (idxPrice === -1) idxPrice = 5;
if (idxStock === -1) idxStock = 7;
if (idxDoc === -1) idxDoc = 8;

const startRow = headerRowIdx + 2;
const products = [];

for (let i = startRow; i < rows.length; i++) {
  const row = rows[i];
  if (row.length <= idxName) continue;

  const name = row[idxName] ? row[idxName].trim() : '';
  if (!name || name.toLowerCase().includes('suplemento')) continue;

  const rawPrice = (row[idxPrice] || '').replace(/[$\s]/g, '').replace(/\./g, '').replace(',', '');
  const price = rawPrice ? parseInt(rawPrice, 10) : 0;
  if (isNaN(price) || price === 0) continue;

  const rawStock = (row[idxStock] || '').trim();
  const stock = rawStock ? parseInt(rawStock, 10) : 100;

  const category = (row[idxCategory] || 'Otros').trim();
  const googleDocUrl = idxDoc >= 0 && row[idxDoc] ? row[idxDoc].trim() : '';

  products.push({
    name,
    price,
    stock: isNaN(stock) ? 100 : stock,
    category,
    google_doc_url: googleDocUrl || null,
    image_url: '/logo.png'
  });
}

return products.map(p => ({ json: p }));

const productData = $('🧩 Parsear CSV → Productos').item.json;
const binary = $input.first().binary;

if (!binary || !binary.data) {
  return [{ json: { ...productData } }];
}

const sections = {
  description: '',
  origin: '',
  ingredients: '',
  usage: '',
  precautions: '',
  extracted_benefits: []
};

try {
  const b64 = binary.data.data || binary.data;
  const buf = Buffer.from(b64, 'base64');
  const rawXml = buf.toString('latin1');

  const textMatches = rawXml.match(/<w:t[^>]*>([^<]+)<\/w:t>/g) || [];
  const paragraphs = [];
  let current = '';

  for (const m of textMatches) {
    const text = m.replace(/<[^>]+>/g, '').trim();
    if (!text) continue;
    if (rawXml.includes('<w:p ') || rawXml.includes('<w:p>')) {
      current += text + ' ';
    } else {
      current += text + ' ';
    }
  }

  const lines = current.split(/(?<=[.!?])\s{2,}|\n/);

  const SECTION_KEYWORDS = {
    description: ['descripci', 'descripcion del producto', 'descripcion del tipo'],
    origin: ['zona de producci', 'lugar de producci'],
    ingredients: ['ingrediente', 'composici', 'f\u00f3rmula', 'formula', 'composi'],
    usage: ['modo de uso', 'instrucciones', 'c\u00f3mo tomar', 'como tomar', 'dosis'],
    precautions: ['precauci', 'advertencia', 'contraindicaci', 'cuidado']
  };

  let currentKey = null;
  let introCapured = false;

  for (const rawLine of lines) {
    const t = rawLine.trim();
    if (!t || t.length < 3) continue;
    const lower = t.toLowerCase();

    if (/^[•\-\*]\s/.test(t)) {
      sections.extracted_benefits.push(t.replace(/^[•\-\*]\s*/, '').trim());
      continue;
    }

    let matched = false;
    for (const [key, kws] of Object.entries(SECTION_KEYWORDS)) {
      if (kws.some(kw => lower.includes(kw))) {
        currentKey = key;
        const afterColon = t.includes(':') ? t.split(':').slice(1).join(':').trim() : '';
        if (afterColon) sections[key] += afterColon + ' ';
        matched = true;
        break;
      }
    }
    if (matched) continue;

    if (!currentKey && !introCapured && t.length > 60) {
      sections.description = t;
      introCapured = true;
      continue;
    }

    if (currentKey) sections[currentKey] += t + ' ';
  }

  for (const k of ['description','origin','ingredients','usage','precautions']) {
    sections[k] = sections[k].trim();
  }

  return [{ json: { ...productData, ...sections } }];

} catch(e) {
  return [{ json: { ...productData } }];
}

const allItems = $input.all();
const now = new Date().toISOString();
const successful = allItems.filter(i => !i.json.error).length;
const failed = allItems.filter(i => i.json.error).length;

return [{
  json: {
    success: true,
    timestamp: now,
    summary: {
      processed: allItems.length,
      successful,
      failed,
      message: `Sincronización completada: ${successful} productos actualizados en Supabase. ${failed} errores.`
    }
  }
}];
